const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: { storyKeys: [], filterClause: '1=0' } }];
}

const storyKeys = items
  .map(item => item.json.story)
  .filter(k => k && k.trim() !== '');

if (storyKeys.length === 0) {
  return [{ json: { storyKeys: [], filterClause: '1=0' } }];
}

const filterClause = storyKeys
  .map(k => `t.jira_ids LIKE '%${k}%'`)
  .join(' OR ');

return [{ json: { storyKeys, filterClause } }];

const allJiraRows = $('Get Accounting Jira Issues').all().map(i => i.json);
const allZdRows = $('Get Linked Zendesk Tickets').all().map(i => i.json);

const today = DateTime.now().setZone('UTC').toFormat('yyyy-MM-dd');

const uniqueStories = {};
for (const row of allJiraRows) {
  if (!row.story) continue;
  if (!uniqueStories[row.story]) {
    uniqueStories[row.story] = {
      story: row.story,
      story_summary: row.story_summary || '(no summary)',
      story_status: row.story_status || 'Unknown',
      story_url: row.story_url || '',
      team: row.team || 'N/A',
      PM: row.PM || 'N/A',
      tickets: []
    };
  }
}

for (const zd of allZdRows) {
  if (!zd.jira_ids) continue;
  for (const storyKey of Object.keys(uniqueStories)) {
    if (zd.jira_ids.includes(storyKey)) {
      uniqueStories[storyKey].tickets.push(zd);
      break;
    }
  }
}

const storyList = Object.values(uniqueStories);
const lines = [];
lines.push('*:clipboard: Daily Accounting Jira Report -- ' + today + '*');
lines.push('_Open Jira stories labeled Accounting with linked Zendesk tickets_');
lines.push('');

for (const s of storyList) {
  const urlPart = s.story_url ? '<' + s.story_url + '|' + s.story + '>' : s.story;
  lines.push('*' + urlPart + ' -- ' + s.story_summary + '*');
  lines.push('Status: ' + s.story_status + ' | Team: ' + s.team + ' | PM: ' + s.PM);
  if (s.tickets.length === 0) {
    lines.push('  - No linked open/pending Zendesk tickets');
  } else {
    for (const t of s.tickets) {
      lines.push('  - ZD #' + t.ticket_id + ' -- "' + (t.subject || 'No subject') + '" | ' + t.ticket_status + ' | ' + (t.account_name || 'Unknown account') + ' | Assignee: ' + (t.assignee_name || 'Unassigned'));
    }
  }
  lines.push('');
}

const totalZd = storyList.reduce((sum, s) => sum + s.tickets.length, 0);
lines.push('*Total: ' + storyList.length + ' Jira stories | ' + totalZd + ' linked open/pending Zendesk tickets*');

return [{ json: { slackMessage: lines.join('\n') } }];
